class Solution {
    public List<Integer> splitIntoFibonacci(String num) {
        List<Integer> result = new ArrayList<>();
        backtrack(num, result, 0);
        return result;
    }

    private boolean backtrack(String num, List<Integer> result, int index) {
        if (index == num.length()) {
            return result.size() >= 3;
        }
        long current = 0;
        for (int i = index; i < num.length(); i++) {
            if (i > index && num.charAt(index) == '0') {
                return false;
            }
            current = current * 10 + num.charAt(i) - '0';
            if (current > Integer.MAX_VALUE) {
                return false;
            }
            if (result.size() >= 2 && current > result.get(result.size() - 1) + result.get(result.size() - 2)) {
                return false;
            }
            if (result.size() < 2 || current == result.get(result.size() - 1) || current == result.get(result.size() - 2)) {
                result.add((int) current);
                if (backtrack(num, result, i + 1)) {
                    return true;
                }
                result.remove(result.size() - 1);
            }
        }
        return false;
    }
}
